import { defineComponentStyle } from "@yamada-ui/react"

export const linkStyle = defineComponentStyle({
  base: {
    alignItems: "center",
    cursor: "pointer",
    display: "inline-flex",
    gap: "3",
    rounded: "l1",
  },

  variants: {
    plain: {
      color: "colorScheme.solid",
      _hover: {
        textDecoration: "underline",
        textDecorationColor: "currentColor",
        textUnderlineOffset: "3px",
      },
    },
    underline: {
      color: "colorScheme.solid",
      textDecoration: "underline",
      textDecorationColor: "currentColor",
      textUnderlineOffset: "3px",
    },
  },

  defaultProps: {
    colorScheme: "link",
    variant: "plain",
  },
})

export type LinkStyle = typeof linkStyle

import { a11y, page, render } from "#test/browser"
import { Link } from "."

describe("<Link />", () => {
  test("renders component correctly", async () => {
    // Default Link color pair against `UIProvider` theme background fails axe-core's
    // color-contrast check in browser mode. The component's rendered color is
    // theme-defined, so this is a theme-level audit item rather than a test bug.
    await a11y(<Link href="https://yamada-ui.com">Link</Link>, {
      axeOptions: { rules: { "color-contrast": { enabled: false } } },
    })
  })

  test("sets `displayName` correctly", () => {
    expect(Link.displayName).toBe("Link")
  })

  test("sets `className` correctly", async () => {
    await render(<Link href="https://yamada-ui.com">Link</Link>)

    await expect.element(page.getByRole("link")).toHaveClass("ui-link")
  })

  test("renders HTML tag correctly", async () => {
    await render(<Link href="https://yamada-ui.com">Link</Link>)

    const link = page.getByRole("link").element()

    expect(link).toBeInstanceOf(HTMLAnchorElement)
  })

  test("should open link in a new tab", async () => {
    await render(
      <Link href="https://yamada-ui.com" external>
        Link
      </Link>,
    )

    const link = page.getByRole("link")

    await expect.element(link).toHaveAttribute("target", "_blank")
    await expect.element(link).toHaveAttribute("rel", "noopener")
  })
})

"use client"

import type { HTMLStyledProps, ThemeProps } from "@yamada-ui/react"
import type { LinkStyle } from "./link.style"
import { createComponent } from "@yamada-ui/react"
import { linkStyle } from "./link.style"

export interface LinkProps extends HTMLStyledProps<"a">, ThemeProps<LinkStyle> {
  /**
   * If `true`, the link will open in new tab.
   *
   * @default false
   */
  external?: boolean
}

const {
  PropsContext: LinkPropsContext,
  usePropsContext: useLinkPropsContext,
  withContext,
} = createComponent<LinkProps, LinkStyle>("link", linkStyle)

export { LinkPropsContext, useLinkPropsContext }

/**
 * `Link` is a component for creating hyperlinks to different web pages, locations within the same page, or other URLs.
 *
 * @see https://yamada-ui.com/docs/components/link
 */
export const Link = withContext("a")(undefined, ({ external, ...rest }) => ({
  rel: external ? "noopener" : undefined,
  target: external ? "_blank" : undefined,
  ...rest,
}))
